mapper.select:
SELECT COUNT(*) FROM hm_query.collection_flat

    AND featured = #{featured}
    AND active = #{active}
    AND type = #{type}
    AND collection_name ILIKE CONCAT('%', #{name}, '%')
    AND (collection_name ILIKE CONCAT('%', #{q}, '%') OR slug ILIKE CONCAT('%', #{q}, '%') OR type ILIKE CONCAT('%', #{q}, '%'))

SELECT cl.collection_id as ID, cl.collection_name as name, cl.slug as slug, '' as description, cl.type as type, cl.image_url as image_url, cl.featured as featured, cl.active as active, cl.product_count as product_count FROM hm_query.collection_flat cl
AND cl.featured = #{featured} AND cl.active = #{active} AND cl.type = #{type} AND cl.collection_name ILIKE CONCAT('%', #{name}, '%') AND (cl.collection_name ILIKE CONCAT('%', #{q}, '%') OR cl.slug ILIKE CONCAT('%', #{q}, '%') OR cl.type ILIKE CONCAT('%', #{q}, '%'))
${orderby} ${pagination}
